var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"악인이란 무엇인가?","JPN":"悪人とは何か。","ENG":"What is a sinner?","TWN":"什麼是惡人？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"우리가 배워온 정의에 따르면, 죄를 거리낌 없이 행하는 것이 바로 악인이다.","JPN":"我々が教わってきた定義によると、何の躊躇いもなく罪を犯す者を指す。","ENG":"We were taught that sinners were ones who sin without hesitation.","TWN":"根據我們所學到的定義，肆無忌憚地犯罪的人就是惡人。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 때로는, 대의라는 명목이 우리가 아는 죄의 의미를 혼란스럽게 한다.","JPN":"だが時には、大儀という名分が我々の知る罪の意味を混乱させる。","ENG":"However, our definition of sin is muddled when it is done under the pretext of a greater cause.","TWN":"但有時，大義的名義會混淆我們對於罪的定義。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"죄를 행한 악인을 악인으로서 규명 짓지 못하게 한다.","JPN":"罪を犯した悪人を、悪人として糾明することを妨げる。","ENG":"It bars us from branding those who have sinned as sinners.","TWN":"我們無法將犯下罪過的惡人定義為惡人。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"희생이란 이름의 눈부신 허울이 그 끔찍한 핏빛을 바래게 한다.","JPN":"犠牲という名の眩いうわべが、その残酷な血の色を色あせるようにする。","ENG":"The brilliant facade called sacrifice is enough to desaturate the crimson red from one's bloodied hands.","TWN":"名為犧牲的冠冕堂皇的外衣會暗淡那可怕的血光。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"대의를 교리로 삼은 세상에서 우리는 무슨 수로 죄를 규명하고 악인을 변별하는가…?","JPN":"大儀を教理とした世界で、我々はどうやって罪を糾明し、悪人を弁別するか……？","ENG":"In a world that views the greater cause as its doctrine, how are we to scrutinize sin and distinguish sinners...?","TWN":"在這個將大義作為教義的世界裡，我們該如何辨別罪惡、分辨惡人……？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"어쩌면…","JPN":"もしかしたら……","ENG":"Perhaps...","TWN":"也許……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"세상의 종말이 예견된 순간부터, 답은 정해져 있었던 걸도 모른다.","JPN":"世界の終末が予見された瞬間から、答えは決められていたのかも知れない。","ENG":"The answer was determined from the moment the end was foreseen.","TWN":"在遇見世界末日的那一刻起，答案便已揭曉。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"위대한 정적이시여. 종막으로 향하는 태양문이 열렸습니다.","JPN":"偉大なる静寂よ。終幕への太陽の門が開かれました。","ENG":"O, Great Silence. The Solar Gates to the denouement have opened.","TWN":"偉大的寂靜，通往末世的太陽門已經開啟。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"마왕이란 이름의 불협화음이 제거된 뒤엔, 저희의 세계도 다시금 평화를 되찾겠죠.","JPN":"魔王という名の不協和音が排除された暁には、私たちの世界もまた平和を取り戻すでしょう。","ENG":"After removing the dissonance called Demon Lord, peace shall once again be restored to our world.","TWN":"排除名為不和諧音的魔王之後，我們的世界將再次恢復和平。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Indeed.","TWN":"是的。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"허나 세계를 지탱해야 할 뿌리가 썩어버린 이상 새로운 위협은 계속해서 눈을 뜨겠지.","JPN":"だが、世界を支えるべきの根が腐ってしまった以上、新しい脅威は続々と目覚めるであろう。","ENG":"However, the roots that sustain this very world have rotted, and new threats will continue to emerge.","TWN":"但是，支撐世界的根基已經腐朽，新的威脅會不斷甦醒。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"마왕을 토벌해 종말로부터 잠시나마 유예를 얻는 것. 그것으로 이번 원정의 목적은 충분히 달성하는 셈입니다.","JPN":"魔王を討伐し、少しでも終末までの猶予を得ること。それでこの遠征の目的は十分達成するわけです。","ENG":"Vanquishing the Demon Lord and delaying the end will be more than enough progress for this expedition.","TWN":"打敗魔王，在末日降臨之前獲得短暫的喘息機會，本次遠征的目的就充分達成了。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"하지만 저희의 연구가 결실을 맺게 되면… 그땐 비로소 종말의 위협에서 해방되어, 영원한 평화를 얻을 수 있겠죠.","JPN":"ですが、私たちの研究が実を結べば……私たちはついに終末の脅威から解放され、永遠の平和を享受するでしょう。","ENG":"And when our research comes to fruition... we will finally be free of the looming threat of the end and attain eternal tranquility.","TWN":"但是，如果我們的研究取得成果……我們將真正擺脫世界末日的威脅，獲得永恆的和平。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"우리의 성무는 이 세계, 엘리시온의 존속을 바라는 이들의 믿음에 부응하는 것이다.","JPN":"我々の聖務はこの世界、エリシオンの存続を望む者たちの信仰に応えることだ。","ENG":"Our sacred mission is to answer the faith of those who wish to see Elysion's continued existence.","TWN":"我們的聖務是不辜負那些希望這個艾利森世界的存續之人們的信賴。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그들의 믿음을 저버리지 마라, 네퀴티아.","JPN":"彼らの信仰を裏切るでないぞ、ネキティア。","ENG":"Do not betray their trust, Nequitia.","TWN":"不要辜負他們的信仰，莉奎蒂亞。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"…물론입니다, 예하.","JPN":"……もちろんです、猊下。","ENG":"...Of course, Your Eminence.","TWN":"……當然了，主教。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};